def cjk(ch: str) -> bool:
    return "\u4e00" <= ch <= "\u9fff"


def build_vocab_meta(vocab: list[dict[str, Any]]):
    rows = []
    min_level: dict[str, int] = {}
    levels_by_word: dict[str, set[int]] = defaultdict(set)
    by_word: dict[str, dict[str, Any]] = {}
    for i, card in enumerate(vocab):
        word = str(card.get("hanzi", ""))
        level = af.inferred_vocab_level(i)
        rows.append({"index": i + 1, "level": level, **card})
        min_level[word] = min(level, min_level.get(word, 99))
        levels_by_word[word].add(level)
        by_word.setdefault(word, card)
    return rows, min_level, levels_by_word, by_word


def segment(text: str, vocab_words: set[str]) -> list[str]:
    max_len = max(map(len, vocab_words)) if vocab_words else 0
    return af.segment_chinese_with_vocab(text, vocab_words, max_len)


def coverage_tokens(text: str, vocab_words: set[str]) -> set[str]:
    """Vocabulary tokens used for coverage and vocabTags.

    Most words are counted by longest-match segmentation. A small set of suffix
    or component entries is also counted when it appears in surface text, because
    forcing these entries to stand alone creates unnatural cards.
    """
    tokens = set(segment(text, vocab_words))
    for word in BOUND_SURFACE_WORDS:
        if word in text and word in vocab_words:
            tokens.add(word)
    return tokens


def segment_with_unknown(text: str, vocab_words: set[str]) -> tuple[list[str], list[str]]:
    max_len = max(map(len, vocab_words)) if vocab_words else 0
    tokens: list[str] = []
    unknown: list[str] = []
    i = 0
    while i < len(text):
        match = ""
        for length in range(min(max_len, len(text) - i), 0, -1):
            candidate = text[i:i + length]
            if candidate in vocab_words:
                match = candidate
                break
        if match:
            tokens.append(match)
            i += len(match)
        else:
            if cjk(text[i]):
                unknown.append(text[i])
            i += 1
    return tokens, unknown


def validate_sentence(level: int, chinese: str, allowed_words: set[str], full_words: set[str], min_level: dict[str, int]) -> None:
    _allowed_tokens, unknown_allowed = segment_with_unknown(chinese, allowed_words)
    full_tokens, unknown_full = segment_with_unknown(chinese, full_words)
    high_tokens = sorted({tok for tok in full_tokens if min_level.get(tok, 99) > level})
    unknown = sorted(set(unknown_allowed + unknown_full))
    if unknown or high_tokens:
        raise ValueError(f"Sentence validation failed L{level} {chinese!r}: unknown={unknown}, high={high_tokens}")


def replace_standalone_mei(text: str) -> str:
    # Replace standalone 没 used as a negator with 没有, while preserving in-vocab
    # words 没有, 没事, 没关系, and 没意思.
    return re.sub(r"没(?!有|事|关系|意思)", "没有", text)


def patch_existing_cards(cards: list[dict[str, Any]], full_words: set[str]) -> list[dict[str, Any]]:
    patched = []
    for card in cards:
        cid = str(card.get("id") or "")
        if GENERATED_ID_RE.match(cid):
            continue
        card = dict(card)
        if cid in PATCHES:
            card.update(PATCHES[cid])
        for key in ("front", "back", "chinese"):
            if isinstance(card.get(key), str):
                card[key] = replace_standalone_mei(card[key])
        chinese = str(card.get("chinese") or (card.get("back") if card.get("direction") == "en_to_zh" else card.get("front")) or "")
        card["chinese"] = chinese
        card["vocabTags"] = sorted(coverage_tokens(chinese, full_words), key=lambda x: (len(x), x))
        patched.append(card)
    return patched


def make_card(card_id: str, level: int, chinese: str, english: str, direction: str, grammar_tags: list[str], vocab_tags: set[str]) -> dict[str, Any]:
    deck_name = f"HSK {level} sentence cards — 2026 syllabus aligned"
    if direction == "en_to_zh":
        front = english
        back = chinese
    else:
        direction = "zh_to_en"
        front = chinese
        back = english
    return {
        "id": card_id,
        "level": level,
        "deckId": f"sentence_hsk{level}",
        "deckName": deck_name,
        "direction": direction,
        "front": front,
        "back": back,
        "chinese": chinese,
        "english": english,
        "grammarTags": grammar_tags,
        "vocabTags": sorted(vocab_tags, key=lambda x: (len(x), x)),
        "tags": [f"hsk{level}", "hsk2026", "sentence", direction, "coverage_augmented"],
    }


def add_seed_cards(existing: list[dict[str, Any]], full_words: set[str], allowed_by_level: dict[int, set[str]], min_level: dict[str, int]) -> list[dict[str, Any]]:
    existing_chinese = {str(card.get("chinese") or "") for card in existing}
    cards: list[dict[str, Any]] = []
    direction_cycle = ["zh_to_en", "en_to_zh", "zh_to_en"]
    for n, (level, chinese, english, grammar_tags) in enumerate(SEED_SENTENCES, start=1):
        level = int(level)
        if chinese in existing_chinese:
            continue
        validate_sentence(level, chinese, allowed_by_level[level], full_words, min_level)
        direction = direction_cycle[(n - 1) % len(direction_cycle)]
        cards.append(make_card(
            f"hsk{level}_sent_aug_seed_{n:03d}", level, chinese, english, direction, list(grammar_tags), coverage_tokens(chinese, full_words)
        ))
        existing_chinese.add(chinese)
    return cards


def add_dense_cards(existing: list[dict[str, Any]], full_words: set[str], allowed_by_level: dict[int, set[str]], min_level: dict[str, int]) -> list[dict[str, Any]]:
    existing_chinese = {str(card.get("chinese") or "") for card in existing}
    cards: list[dict[str, Any]] = []
    serial_by_level = {1: 0, 2: 0, 3: 0}
    direction_cycle = ["zh_to_en", "zh_to_en", "en_to_zh"]
    for level, chinese, english in DENSE_SENTENCES:
        level = int(level)
        if chinese in existing_chinese:
            continue
        validate_sentence(level, chinese, allowed_by_level[level], full_words, min_level)
        serial_by_level[level] += 1
        direction = direction_cycle[(serial_by_level[level] - 1) % len(direction_cycle)]
        cards.append(make_card(
            f"hsk{level}_sent_aug_dense_{serial_by_level[level]:04d}",
            level,
            chinese,
            english,
            direction,
            ["coverage", "natural sentence"],
            coverage_tokens(chinese, full_words),
        ))
        existing_chinese.add(chinese)
    return cards


def write_sentence_parts(cards: list[dict[str, Any]]) -> int:
    for path in DATA_DIR.glob("sentence-cards-data-part-*.js"):
        path.unlink()
    for part_index, start in enumerate(range(0, len(cards), CHUNK_SIZE), start=1):
        chunk = cards[start:start + CHUNK_SIZE]
        path = DATA_DIR / f"sentence-cards-data-part-{part_index}.js"
        lines = [
            "(function(){",
            "window.HSK_SENTENCE_CARDS=window.HSK_SENTENCE_CARDS||[];",
            "window.HSK_SENTENCE_CARDS.push(",
        ]
        for i, card in enumerate(chunk):
            suffix = "," if i < len(chunk) - 1 else ""
            lines.append(json.dumps(card, ensure_ascii=False, separators=(",", ":")) + suffix)
        lines += [");", "})();", ""]
        path.write_text("\n".join(lines), encoding="utf-8")
    return (len(cards) + CHUNK_SIZE - 1) // CHUNK_SIZE


def update_index_html(part_count: int) -> None:
    path = ROOT / "index.html"
    html = path.read_text(encoding="utf-8")
    block = "\n".join(
        f'  <script src="js/data/flashcards/sentence-cards-data-part-{i}.js"></script>'
        for i in range(1, part_count + 1)
    )
    html = re.sub(
        r'(?:\s*<script src="js/data/flashcards/sentence-cards-data-part-\d+\.js"></script>)+',
        "\n" + block,
        html,
        count=1,
    )
    path.write_text(html, encoding="utf-8")


def update_line_counts() -> None:
    rows = []
    for path in sorted(ROOT.glob("**/*.js")):
        if "__pycache__" in path.parts:
            continue
        rel = path.relative_to(ROOT)
        rows.append(f"{len(path.read_text(encoding='utf-8').splitlines()):6d} ./{rel}")
    (ROOT / "JS_LINE_COUNTS.txt").write_text("\n".join(rows) + "\n", encoding="utf-8")


def build_counts(cards: list[dict[str, Any]], full_words: set[str], level_words: dict[int, set[str]]) -> dict[int, Counter[str]]:
    counts = {1: Counter(), 2: Counter(), 3: Counter()}
    for card in cards:
        level = int(card.get("level") or 0)
        if level not in counts:
            continue
        chinese = str(card.get("chinese") or "")
        for tok in coverage_tokens(chinese, full_words):
            if tok in level_words[level]:
                counts[level][tok] += 1
    return counts


def write_summary(cards: list[dict[str, Any]], patched_count: int, seed_count: int, dense_count: int, rows: list[dict[str, Any]], full_words: set[str], part_count: int) -> None:
    level_words = {level: {row["hanzi"] for row in rows if row["level"] == level} for level in (1, 2, 3)}
    counts = build_counts(cards, full_words, level_words)
    summary: dict[str, Any] = {
        "existingPatchedCards": patched_count,
        "seedCardsAdded": seed_count,
        "denseCoverageCardsAdded": dense_count,
        "totalSentenceCards": len(cards),
        "sentenceDataParts": part_count,
        "coverageMethod": "longest-match segmentation plus component-surface count for 们、子、室、园、员",
        "sameLevelCoverage": {},
    }
    for level in (1, 2, 3):
        vals = [counts[level][row["hanzi"]] for row in rows if row["level"] == level]
        summary["sameLevelCoverage"][str(level)] = {
            "vocabularyCards": len(vals),
            "minSameLevelCoverageCount": min(vals),
            "averageSameLevelCoverageCount": round(sum(vals) / len(vals), 2),
            "belowThree": sum(v < TARGET_MIN for v in vals),
        }
    out = ROOT / "tests" / "reports" / "sentence_augmentation_summary.json"
    out.parent.mkdir(parents=True, exist_ok=True)
    out.write_text(json.dumps(summary, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    print(json.dumps(summary, ensure_ascii=False, indent=2))


def main() -> None:
    if "--legacy-direct-write" not in sys.argv[1:]:
        raise SystemExit(
            "This legacy tool writes generated JavaScript directly. Use "
            "language/scripts/audit_catalog.py and compile_runtime_catalog.py, "
            "or pass --legacy-direct-write only for an intentional historical rebuild."
        )
    data = af.load_all()
    vocab = data["vocabulary"]
    rows, min_level, _levels_by_word, _by_word = build_vocab_meta(vocab)
    full_words = {str(card.get("hanzi")) for card in vocab if card.get("hanzi")}
    allowed_by_level = {level: {row["hanzi"] for row in rows if row["level"] <= level} for level in (1, 2, 3)}

    patched = patch_existing_cards(data["sentences"], full_words)
    seed_cards = add_seed_cards(patched, full_words, allowed_by_level, min_level)
    dense_cards = add_dense_cards(patched + seed_cards, full_words, allowed_by_level, min_level)
    cards = patched + seed_cards + dense_cards

    for card in cards:
        chinese = str(card.get("chinese") or "")
        card["vocabTags"] = sorted(coverage_tokens(chinese, full_words), key=lambda x: (len(x), x))

    part_count = write_sentence_parts(cards)
    update_index_html(part_count)
    update_line_counts()
    write_summary(cards, len(patched), len(seed_cards), len(dense_cards), rows, full_words, part_count)


if __name__ == "__main__":
    main()
